import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  // --- 1. DEFENSIVE PARSER ---
  const safeParseHoldings = (data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      // Handle double-stringified JSON common in some Postgres drivers
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      console.error("Corrupted holdings data:", e);
      return [];
    }
  };

  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: Delete this strategy?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("STRATEGY_DELETED");
    } catch (err) {
      toast.error("WIPE_FAILED: DB_LOCK_ERROR");
    }
  };

  const handleDownload = async (item) => {
    const toastId = toast.loading("SYNTHESIZING_PDF...");
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data], { type: 'application/pdf' }));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Finify_Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      
      // Cleanup
      link.remove();
      window.URL.revokeObjectURL(url); 
      toast.success("PDF_READY", { id: toastId });
    } catch (err) {
      toast.error("PDF_SYNTHESIS_FAILED", { id: toastId });
    }
  };

  // Close modal on Escape key
  useEffect(() => {
    const handleEsc = (e) => {
      if (e.key === 'Escape') setSelectedItem(null);
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  // Prevent background scroll when modal is open
  useEffect(() => {
    document.body.style.overflow = selectedItem ? 'hidden' : 'unset';
  }, [selectedItem]);

  useEffect(() => { fetchHistory(); }, []);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      <div style={headerRow}>
        <h2 style={headerStyle}><Archive size={20} color="var(--accent-primary, #10b981)"/> STRATEGY_VAULT</h2>
        <span style={nodeCount}>{history.length} NODES_STORED</span>
      </div>
      
      {history.length === 0 ? (
        <div style={emptyStyle}>No records found. Initialize a new strategy to populate the vault.</div>
      ) : (
        <div style={listStyle}>
          {history.map((item) => (
            <div key={item.id} style={cardStyle}>
              <div style={{ flex: 1 }}>
                <div style={tagRow}>
                  <span style={dateTag}>
                    <Calendar size={10}/> {new Date(item.created_at).toLocaleDateString()}
                  </span>
                  <span style={riskTag}>
                    <ShieldCheck size={10}/> RISK_SCORE: {item.risk_score || 'N/A'}
                  </span>
                </div>
                <h4 style={titleStyle}>{item.goal || "Untitled Strategy"}</h4>
                
                <div style={tickerRow}>
                   {safeParseHoldings(item.holdings).map((t, i) => (
                     <span key={`${item.id}-ticker-${i}`} style={tickerTag}>{t}</span>
                   ))}
                </div>
              </div>

              <div style={actionRow}>
                <button onClick={() => setSelectedItem(item)} style={iconBtn} title="View Rationale"><Eye size={18}/></button>
                <button onClick={() => handleDownload(item)} style={iconBtn} title="Download PDF"><Download size={18}/></button>
                <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Delete Record"><Trash2 size={18}/></button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* --- STRATEGY PREVIEW MODAL --- */}
      {selectedItem && (
        <div 
          style={modalOverlay} 
          onClick={() => setSelectedItem(null)} 
          role="dialog" 
          aria-modal="true"
        >
          <div style={modalContent} onClick={e => e.stopPropagation()}>
            <div style={modalHeader}>
              <h3 style={{margin: 0, fontSize: '0.8rem', fontFamily: 'monospace'}}>
                STRATEGY_PREVIEW // ID_{selectedItem.id}
              </h3>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}><X size={20}/></button>
            </div>
            <div style={modalBody}>
              <p style={modalLabel}>SUMMARY</p>
              <p style={modalText}>{selectedItem.summary || "No summary available."}</p>
              <hr style={divider}/>
              <p style={modalLabel}>AGENTIC_RATIONALE</p>
              <p style={modalText}>{selectedItem.rationale || "No rationale provided."}</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* --- Terminal UI Styles (Enhanced) --- */
const containerStyle = { padding: '2rem 1.5rem', maxWidth: '1000px', margin: '0 auto', minHeight: '80vh' };
const headerRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem', borderBottom: '1px solid var(--surface-border, #27272a)', paddingBottom: '1rem' };
const headerStyle = { color: 'var(--text-primary, #ffffff)', display: 'flex', alignItems: 'center', gap: '12px', fontSize: '1.2rem', letterSpacing: '0.1em', margin: 0 };
const nodeCount = { fontSize: '0.65rem', color: 'var(--text-muted, #71717a)', fontFamily: 'monospace' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '1.2rem' };
const cardStyle = { display: 'flex', padding: '1.5rem', background: 'var(--surface-glass, rgba(24, 24, 27, 0.8))', border: '1px solid var(--surface-border, #27272a)', borderRadius: '16px', gap: '1.5rem', position: 'relative', transition: 'transform 0.2s ease' };
